import { describe, it, expect } from 'vitest';
import { execSync } from 'child_process';
import { existsSync } from 'fs';
import { resolve } from 'path';

describe('US-001: Production build', () => {
  it('npm run build exits with code 0', () => {
    expect(() => execSync('npm run build', { stdio: 'pipe' })).not.toThrow();
  });

  it('dist/index.html is generated', () => {
    execSync('npm run build', { stdio: 'pipe' });
    expect(existsSync(resolve(__dirname, '..', 'dist', 'index.html'))).toBe(true);
  });
});

import { describe, it, expect, beforeEach } from 'vitest';

describe('US-001: Canvas container', () => {
  beforeEach(() => {
    document.body.innerHTML = '<div id="app"></div>';
  });

  it('renders a <canvas> element inside #app', async () => {
    await import('../src/main');
    const canvas = document.querySelector('#app canvas');
    expect(canvas).not.toBeNull();
    expect(canvas?.tagName.toLowerCase()).toBe('canvas');
  });

  it('canvas has non-zero dimensions', async () => {
    // jsdom defaults innerWidth/innerHeight to 0; set them for the test
    Object.defineProperty(window, 'innerWidth', { value: 1024, writable: true });
    Object.defineProperty(window, 'innerHeight', { value: 768, writable: true });
    await import('../src/main');
    const canvas = document.querySelector('#app canvas') as HTMLCanvasElement | null;
    expect(canvas).not.toBeNull();
    expect(canvas!.width).toBeGreaterThan(0);
    expect(canvas!.height).toBeGreaterThan(0);
  });
});

import { describe, it, expect, vi, beforeEach } from 'vitest';

describe('US-001: No forbidden storage APIs', () => {
  beforeEach(() => {
    document.body.innerHTML = '<div id="app"></div>';
  });

  it('does not access localStorage', async () => {
    const getItemSpy = vi.spyOn(Storage.prototype, 'getItem');
    const setItemSpy = vi.spyOn(Storage.prototype, 'setItem');
    await import('../src/main');
    expect(getItemSpy).not.toHaveBeenCalled();
    expect(setItemSpy).not.toHaveBeenCalled();
    getItemSpy.mockRestore();
    setItemSpy.mockRestore();
  });

  it('does not set cookies', async () => {
    const cookieSpy = vi.spyOn(document, 'cookie', 'set');
    await import('../src/main');
    expect(cookieSpy).not.toHaveBeenCalled();
    cookieSpy.mockRestore();
  });
});

import { describe, it, expect } from 'vitest';
import { readFileSync } from 'fs';
import { resolve } from 'path';

describe('US-001: index.html structure', () => {
  const html = readFileSync(resolve(__dirname, '..', 'index.html'), 'utf-8');

  it('contains a #app container', () => {
    expect(html).toContain('id="app"');
  });

  it('contains a viewport meta tag', () => {
    expect(html).toMatch(/meta.*name=["']viewport["']/);
  });

  it('loads src/main.ts as a module', () => {
    expect(html).toMatch(/script.*type=["']module["'].*src=["']\/src\/main\.ts["']/);
  });

  it('sets lang attribute to en', () => {
    expect(html).toMatch(/html.*lang=["']en["']/);
  });
});

